input_list = []  # Reset input list variable after every loop iteration so it starts accumulating the integers from next line read by sys.stdin   (# This will ensure that we start adding numbers as soon as possible, instead of waiting until all lines have been processed before starting to add them up) (Python idiom).
# Loop over each integer received on standard input stream: – Python's way for looping through a sequence or collection. It’ll read the next line from sys.stdin and convert it into an int, then accumulate that number in sum until all lines have been processed (# This will ensure we start adding numbers as soon as possible).
