if mean is not None :   # If condition check for both variables being defined and non-None, if so then proceed with printing ("Average:",mean ) (Python idiom) – It’ll print the average of all valid integers in input list (# This will ensure we start adding numbers as soon as possible).
    print("Average:" , mean)   # Print function call followed by variable 'mean' which is printed out. Python prints these strings before it outputs any value (Python idiom) – It’ll print the average of all valid integers in input list (# This will ensure we start adding numbers as soon as possible).
